        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }

        viewModelScope.launch(Dispatchers.IO) {
            val lang = _uiState.value.currentLang
            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
            val config = aiConfigStore.config.first()
            val prompt = """分析${langName}句子："$sentence"
【翻译】中文翻译
