package com.multilanglearner.data.network

import android.content.Context
import android.util.Log
import com.github.yausername.youtubedl_android.YoutubedlApp
import com.github.yausername.youtubedl_android.mapper.VideoInfo
import com.yausername.databindia
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlinx.coroutines.withContext
import java.io.File
import javax.inject.Inject
import javax.inject.Singleton
import kotlin.coroutines.resume
import kotlin.coroutines.resumeWithException

@Singleton
class YoutubeDlService @Inject constructor(
    private val context: Context
) {
    private var initialized = false

    private suspend fun init() {
        if (initialized) return
        withContext(Dispatchers.IO) {
            try {
                YoutubedlApp.initialize(
                    context,
                    File(context.filesDir, "yt-dlp").absolutePath,
                    File(context.filesDir, "ffmpeg").absolutePath
                )
                initialized = true
                Log.d("YoutubeDlService", "YoutubeDL initialized")
            } catch (e: Exception) {
                Log.e("YoutubeDlService", "Failed to initialize", e)
                throw e
            }
        }
    }

    /**
     * 获取视频信息
     */
    suspend fun getVideoInfo(url: String): VideoInfo? = suspendCancellableCoroutine { continuation ->
        val job = kotlinx.coroutines.GlobalScope.launch(Dispatchers.IO) {
            try {
                init()
                val info = YoutubedlApp.getInstance().getInfo(url)
                databindia.bind(info)
                Log.d("YoutubeDlService", "Video info: ${info.title}")
                continuation.resume(info)
            } catch (e: Exception) {
                Log.e("YoutubeDlService", "Failed to get video info", e)
                continuation.resumeWithException(e)
            }
        }
        continuation.invokeOnCancellation {
            job.cancel()
        }
    }

    /**
     * 下载视频
     * @param url 视频 URL
     * @param outputFile 输出文件
     * @param onProgress 进度回调 (0-100)
     */
    suspend fun downloadVideo(
        url: String,
        outputFile: File,
        onProgress: (Int) -> Unit = {}
    ): File = suspendCancellableCoroutine { continuation ->
        val job = kotlinx.coroutines.GlobalScope.launch(Dispatchers.IO) {
            try {
                init()
                outputFile.parentFile?.mkdirs()

                Log.d("YoutubeDlService", "Starting download to: ${outputFile.absolutePath}")

                YoutubedlApp.getInstance().download(
                    url,
                    outputFile.absolutePath,
                    onProgress = { progress ->
                        onProgress(progress.toInt())
                        Log.d("YoutubeDlService", "Download progress: $progress%")
                    },
                    onDone = {
                        Log.d("YoutubeDlService", "Download complete")
                        continuation.resume(outputFile)
                    },
                    onError = { error ->
                        Log.e("YoutubeDlService", "Download error", error)
                        continuation.resumeWithException(error)
                    }
                )
            } catch (e: Exception) {
                Log.e("YoutubeDlService", "Download failed", e)
                continuation.resumeWithException(e)
            }
        }
        continuation.invokeOnCancellation {
            job.cancel()
        }
    }

    /**
     * 从视频中提取音频（用于转录）
     * @param inputFile 视频文件
     * @param outputFile 输出音频文件 (mp3, mono, 16kHz)
     * @param startTimeMs 开始时间（毫秒），0 表示从头开始
     * @param durationMs 时长（毫秒），null 表示到结尾
     * @param maxFileSizeBytes 最大文件大小，超过则需要分段
     */
    suspend fun extractAudio(
        inputFile: File,
        outputFile: File,
        startTimeMs: Long = 0,
        durationMs: Long? = null,
        maxFileSizeBytes: Long = 25 * 1024 * 1024 // 25MB Groq 限制
    ): File = withContext(Dispatchers.IO) {
        try {
            init()
            outputFile.parentFile?.mkdirs()

            // FFmpeg 命令：提取音频并压缩
            // -ss: 开始时间
            // -t: 时长（秒）
            // -i: 输入文件
            // -vn: 无视频
            // -ar: 采样率 16kHz
            // -ac: 单声道
            // -b:a: 比特率 64k（压缩）
            // -acodec libmp3lame: MP3 编码
            val startTimeSec = startTimeMs / 1000.0
            val durationSec = durationMs?.let { it / 1000.0 }

            val cmd = buildList {
                add("-ss"); add("$startTimeSec")
                if (durationSec != null) {
                    add("-t"); add("$durationSec")
                }
                add("-i"); add(inputFile.absolutePath)
                add("-vn")
                add("-ar"); add("16000")
                add("-ac"); add("1")
                add("-b:a"); add("64k")
                add("-acodec"); add("libmp3lame")
                add("-y") // 覆盖输出文件
                add(outputFile.absolutePath)
            }

            Log.d("YoutubeDlService", "FFmpeg command: $cmd")

            val rc = YoutubedlApp.getInstance().executeFfpeg(
                cmd.toTypedArray(),
                emptyArray()
            )

            if (rc != 0) {
                throw Exception("FFmpeg failed with code $rc")
            }

            // 检查文件大小
            if (outputFile.length() > maxFileSizeBytes) {
                Log.w("YoutubeDlService", "Audio file too large: ${outputFile.length()} bytes")
            }

            Log.d("YoutubeDlService", "Audio extracted: ${outputFile.absolutePath}, size: ${outputFile.length()} bytes")

            outputFile
        } catch (e: Exception) {
            Log.e("YoutubeDlService", "Failed to extract audio", e)
            throw e
        }
    }

    /**
     * 获取视频时长（毫秒）
     */
    suspend fun getVideoDuration(file: File): Long = withContext(Dispatchers.IO) {
        try {
            init()
            // 使用 ffprobe 获取时长
            val cmd = arrayOf(
                "-v", "quiet",
                "-print_format", "json",
                "-show_format",
                file.absolutePath
            )

            val output = StringBuilder()
            val rc = YoutubedlApp.getInstance().executeFfpeg(
                cmd,
                emptyArray(),
                object : com.yausername.databindia.StreamCallback {
                    override fun onData(data: ByteArray) {
                        output.append(String(data))
                    }
                }
            )

            if (rc == 0) {
                val json = org.json.JSONObject(output.toString())
                val duration = json.getJSONObject("format").getDouble("duration")
                (duration * 1000).toLong()
            } else {
                0L
            }
        } catch (e: Exception) {
            Log.e("YoutubeDlService", "Failed to get duration", e)
            0L
        }
    }
}

