class SegmentedTranscribeService @Inject constructor(
    @ApplicationContext private val context: Context,
    private val whisperService: WhisperService,
    private val youtubeDlService: YoutubeDlService
) {
    // Groq API 文件大小限制（25MB）
    private val MAX_FILE_SIZE = 25 * 1024 * 1024L

    // 每段时长（10分钟）
    private val SEGMENT_DURATION_MS = 10 * 60 * 1000L

    /**
     * 转录视频文件（支持大文件分段处理）
     * @param videoFile 视频文件
     * @param config AI 配置
     * @param onProgress 进度回调 (当前段, 总段数, 当前任务描述)
     */
    suspend fun transcribeVideo(
        videoFile: File,
        config: AIConfig,
        onProgress: (Int, Int, String) -> Unit = { _, _, _ -> }
    ): TranscriptionResult = withContext(Dispatchers.IO) {

        // 检查 API Key
        val hasGroqKey = config.groqApiKey.isNotBlank() ||
                         (config.provider == "groq" && config.apiKey.isNotBlank())
        if (!hasGroqKey) {
            return@withContext TranscriptionResult(
                success = false,
                error = "请先在 AI 设置中配置 Groq Whisper API Key"
            )
        }

        onProgress(0, 1, "正在分析视频...")

        // 获取视频时长
        val durationMs = youtubeDlService.getVideoDuration(videoFile)
        if (durationMs <= 0) {
            // 无法获取时长，尝试直接转录
            Log.w("SegmentedTranscribeService", "Could not get video duration, trying direct transcription")
            return@withContext transcribeDirect(videoFile, config, onProgress)
        }

        val durationMin = durationMs / 60000.0
        Log.d("SegmentedTranscribeService", "Video duration: ${durationMin.toInt()} min")

        // 计算需要分段的数量
        val segmentCount = Math.ceil(durationMs.toDouble() / SEGMENT_DURATION_MS).toInt()

        if (segmentCount == 1) {
            // 不需要分段，直接转录
            Log.d("SegmentedTranscribeService", "Video is short enough for direct transcription")
            return@withContext transcribeDirect(videoFile, config, onProgress)
        }

        Log.d("SegmentedTranscribeService", "Video needs $segmentCount segments")

        // 分段处理
        val allText = StringBuilder()
        val allWords = mutableListOf<WordTimestamp>()
        var detectedLanguage: String? = null

        // 创建临时目录
        val tempDir = File(context.cacheDir, "transcribe_${System.currentTimeMillis()}")
        tempDir.mkdirs()

        try {
            for (i in 0 until segmentCount) {
                val startTimeMs = i * SEGMENT_DURATION_MS
                val segmentDuration = minOf(SEGMENT_DURATION_MS, durationMs - startTimeMs)

                onProgress(i + 1, segmentCount, "正在提取第 ${i + 1}/$segmentCount 段音频...")

                // 提取音频段
                val audioFile = File(tempDir, "segment_$i.mp3")

                try {
                    youtubeDlService.extractAudio(
                        videoFile,
                        audioFile,
                        startTimeMs = startTimeMs,
                        durationMs = segmentDuration
                    )

                    // 检查音频文件大小
                    if (audioFile.length() > MAX_FILE_SIZE) {
                        // 音频仍然太大，需要进一步压缩或分段
                        Log.w("SegmentedTranscribeService", "Audio segment too large: ${audioFile.length()} bytes")
                        onProgress(i + 1, segmentCount, "第 ${i + 1} 段音频太大，跳过...")
                        continue
                    }

                    onProgress(i + 1, segmentCount, "正在转录第 ${i + 1}/$segmentCount 段...")

                    // 转录
                    val result = whisperService.transcribeGroq(audioFile, config)

                    if (result != null && result.success) {
                        // 调整时间戳偏移
                        val timeOffsetMs = startTimeMs
                        val adjustedWords = result.words.map { wt ->
                            WordTimestamp(
                                w = wt.w,
                                s = wt.s + timeOffsetMs / 1000.0,
                                e = wt.e + timeOffsetMs / 1000.0
                            )
                        }

                        allWords.addAll(adjustedWords)
                        if (allText.isNotEmpty()) allText.append(" ")
                        allText.append(result.text)

                        if (detectedLanguage == null && result.detectedLang.isNotEmpty()) {
                            detectedLanguage = result.detectedLang
                        }

                        Log.d("SegmentedTranscribeService", "Segment $i transcribed: ${result.text.take(50)}...")
                    } else {
                        Log.w("SegmentedTranscribeService", "Segment $i failed: ${result?.error}")
                    }

                } catch (e: Exception) {
                    Log.e("SegmentedTranscribeService", "Error processing segment $i", e)
                } finally {
                    // 删除临时音频文件
                    if (audioFile.exists()) {
                        audioFile.delete()
                    }
                }
            }

            if (allText.isEmpty()) {
                TranscriptionResult(success = false, error = "转录失败，所有段落都无法处理")
            } else {
                TranscriptionResult(
                    success = true,
                    text = allText.toString(),
                    words = allWords,
                    detectedLang = detectedLanguage ?: ""
                )
            }

        } finally {
            // 清理临时目录
            tempDir.deleteRecursively()
        }
    }

    /**
     * 直接转录（用于小文件）
     */
    private suspend fun transcribeDirect(
        videoFile: File,
        config: AIConfig,
        onProgress: (Int, Int, String) -> Unit
    ): TranscriptionResult {
        onProgress(1, 1, "正在转录...")

        // 直接使用视频文件转录
        val result = whisperService.transcribeGroq(videoFile, config)

        return if (result != null && result.success) {
            TranscriptionResult(
                success = true,
                text = result.text,
                words = result.words,
                detectedLang = result.detectedLang
            )
        } else {
            TranscriptionResult(
                success = false,
                error = result?.error ?: "转录失败"
            )
        }
    }
}

/**
 * 转录结果
 */
data class TranscriptionResult(
    val success: Boolean,
    val text: String = "",
    val words: List<WordTimestamp> = emptyList(),
    val detectedLang: String = "",
    val error: String = ""
)

