     */
    suspend fun getVideoDuration(file: File): Long = withContext(Dispatchers.IO) {
        try {
            init()
            val cmd = arrayOf(
                "-v", "quiet",
                "-print_format", "json",
                "-show_format",
                file.absolutePath
            )

            var output = ""
            val rc = YoutubedlApp.getInstance().executeFfpeg(
                cmd,
                emptyArray(),
                object : com.yausername.databindia.StreamCallback {
                    override fun onData(data: ByteArray) {
                        output += String(data)
                    }
                }
            )

            if (rc == 0 && output.isNotEmpty()) {
                try {
                    val json = org.json.JSONObject(output)
                    json.getJSONObject("format").getDouble("duration").toLong() * 1000
                } catch (e: Exception) {
                    // JSON 解析失败，返回估算值
                    (file.length() / 1024 / 60) * 60000 // 假设 1KB/min
