 * 下载视频 - 支持 B站、YouTube 等平台
 */
fun downloadVideo(onComplete: (String, String?) -> Unit) {
    val url = _uiState.value.url.trim()

    if (url.isBlank()) {
        _uiState.update { it.copy(statusText = "请输入视频链接") }
        return
    }

    viewModelScope.launch(Dispatchers.IO) {
        try {
            _uiState.update { it.copy(isDownloading = true, isFetchingInfo = true, statusText = "正在解析视频链接...") }

            val result = videoDownloadService.getVideoInfo(url)

            _uiState.update { it.copy(isFetchingInfo = false) }

            result.onSuccess { videoInfo ->
                _uiState.update { it.copy(statusText = "正在下载: ${videoInfo.title}") }

                val safeTitle = videoInfo.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
                val outputFile = File(downloadsDir, "${safeTitle}_${System.currentTimeMillis()}.mp4")

                try {
                    downloadVideoFile(videoInfo.downloadUrl, safeTitle, outputFile, onComplete)
                } catch (e: Exception) {
                    _uiState.update { it.copy(isDownloading = false, statusText = "下载失败: ${e.message}") }
                }
            }.onFailure { error ->
                _uiState.update { it.copy(isDownloading = false, statusText = "解析失败: ${error.message}\n\n建议：使用导入功能添加本地视频") }
            }

        } catch (e: Exception) {
            android.util.Log.e("HomeViewModel", "Download failed", e)
            _uiState.update { it.copy(isDownloading = false, statusText = "下载失败: ${e.message}") }
        }
    }
}

private suspend fun downloadVideoFile(
    videoUrl: String,
    title: String,
    outputFile: File,
    onComplete: (String, String?) -> Unit
) {
    val request = okhttp3.Request.Builder()
        .url(videoUrl)
        .build()

    val client = okhttp3.OkHttpClient.Builder()
        .connectTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
        .readTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
        .build()

    val response = client.newCall(request).execute()

    if (!response.isSuccessful) {
        throw Exception("HTTP ${response.code}")
    }

    val body = response.body ?: throw Exception("No response body")
    val contentLength = body.contentLength()
    val inputStream = body.byteStream()

    val fileName = "${title}_${System.currentTimeMillis()}.mp4"
    val finalFile = if (outputFile.exists()) File(downloadsDir, fileName) else outputFile

    var bytesCopied = 0L
    val buffer = ByteArray(8 * 1024)
    var bytes: Int

    inputStream.use { input ->
        FileOutputStream(finalFile).use { output ->
            while (input.read(buffer).also { bytes = it } > 0) {
                output.write(buffer, 0, bytes)
                bytesCopied += bytes

